import{bQ as d,aL as a,u as e,G as r}from"./chunks/framework.D06dwy5q.js";const o="/kb/assets/01-access-chain-map.DVssnYp0.png",s="/kb/assets/02-url-dns-boundary.C8FFg_2l.png",n="/kb/assets/03-cdn-cname-switchboard.Bj4xTDYc.png",i="/kb/assets/04-connection-error-fork.DJ66h2x_.png",l="/kb/assets/05-status-layer-triage.BFDUaNzv.png",u=JSON.parse('{"title":"第 1 讲｜一次访问网站","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/01-一次访问网站.md","filePath":"00.互联网与架构基础/01-一次访问网站.md","lastUpdated":null}'),p={name:"00.互联网与架构基础/01-一次访问网站.md"};function c(E,t,h,A,b,g){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="第-1-讲-一次访问网站" tabindex="-1">第 1 讲｜一次访问网站 <a class="header-anchor" href="#第-1-讲-一次访问网站" aria-label="Permalink to &quot;第 1 讲｜一次访问网站&quot;">​</a></h1><p>浏览器输入一个网址回车,看似简单的一步,背后涉及至少五六层不同的技术机制。每一层都可能成为访问失败的原因。理解这一过程的核心目的不是为了&quot;知道有多少步骤&quot;,而是为了<strong>当访问出现问题时,能够准确判断卡在哪一层</strong>——浏览器报 <code>DNS_PROBE_FINISHED_NXDOMAIN</code> 是 DNS 层的问题,显示 502 是入口层到后端的问题,页面打开但接口转圈是后端或数据库的问题。</p><p>本讲围绕一个简单的访问场景,把涉及的核心对象逐一拆开:URL 结构、DNS 解析、TCP/TLS 握手、HTTP 请求、入口层、后端、页面资源加载。每一层都给出对应的判定信号——出现什么现象就指向哪一层的问题。</p><p><img src="'+o+'" alt="一次访问网站的整体链路"></p><h2 id="一、url-结构" tabindex="-1">一、URL 结构 <a class="header-anchor" href="#一、url-结构" aria-label="Permalink to &quot;一、URL 结构&quot;">​</a></h2><p>浏览器地址栏里的完整地址,正式名称是 URL(Uniform Resource Locator)。一个完整的 URL 由六个部分构成:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.example.com:443/docs/index.html?from=notes#title</span></span></code></pre></div><table tabindex="0"><thead><tr><th>部分</th><th>内容</th><th>作用</th></tr></thead><tbody><tr><td>协议</td><td><code>https://</code></td><td>决定通信走 HTTP 还是 HTTPS,后者加密</td></tr><tr><td>域名</td><td><code>www.example.com</code></td><td>要访问的主机名,需通过 DNS 解析为 IP</td></tr><tr><td>端口</td><td><code>443</code></td><td>默认 HTTPS 是 443、HTTP 是 80,可省略</td></tr><tr><td>路径</td><td><code>/docs/index.html</code></td><td>服务器内部的资源位置</td></tr><tr><td>查询参数</td><td><code>?from=notes</code></td><td>传给后端的额外参数,搜索/过滤/分页常用</td></tr><tr><td>片段</td><td><code>#title</code></td><td>浏览器内部使用,跳转到页面锚点,不发送到服务器</td></tr></tbody></table><h3 id="路径不参与-dns-解析" tabindex="-1">路径不参与 DNS 解析 <a class="header-anchor" href="#路径不参与-dns-解析" aria-label="Permalink to &quot;路径不参与 DNS 解析&quot;">​</a></h3><p>一个容易被忽略的关键事实:<strong>DNS 只把域名翻译成 IP,URL 中的路径和后续字段不参与 DNS 解析</strong>。<code>www.example.com/docs</code> 与 <code>www.example.com/api</code> 对 DNS 来说完全相同,返回同一个 IP——路径的处理发生在服务器收到请求之后,Web 服务根据路径将请求分流到不同处理逻辑。</p><p>这一认知决定了排查方向:同一域名下不同路径访问异常,问题不在 DNS,而在 Web 服务的路由配置或后端实现。</p><p><img src="'+s+`" alt="URL 中只有域名进入 DNS 解析"></p><h3 id="片段不发送到服务器" tabindex="-1">片段不发送到服务器 <a class="header-anchor" href="#片段不发送到服务器" aria-label="Permalink to &quot;片段不发送到服务器&quot;">​</a></h3><p>URL 中 <code>#</code> 之后的内容(片段标识符)<strong>完全由浏览器在客户端处理</strong>,不会发送到服务器。在浏览器抓包(Network 面板)中观察到的请求路径不包含 <code>#xxx</code>。这意味着:基于片段的页面跳转(单页应用的路由)不会触发服务器请求,服务器日志中也不会出现这部分内容。</p><h2 id="二、dns-解析" tabindex="-1">二、DNS 解析 <a class="header-anchor" href="#二、dns-解析" aria-label="Permalink to &quot;二、DNS 解析&quot;">​</a></h2><p>机器之间通信使用的是 IP 地址,域名是为方便人类记忆而设计的。浏览器拿到域名后,第一步就是查询该域名对应的 IP——这个过程称为 DNS(Domain Name System)解析。DNS 的作用类似电话查号台:用户记得住名称,但通信需要号码,DNS 完成两者之间的翻译。</p><h3 id="常见-dns-记录类型" tabindex="-1">常见 DNS 记录类型 <a class="header-anchor" href="#常见-dns-记录类型" aria-label="Permalink to &quot;常见 DNS 记录类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>记录类型</th><th>返回内容</th><th>典型用途</th></tr></thead><tbody><tr><td>A</td><td>IPv4 地址</td><td>最常见,绝大多数业务域名使用 A 记录</td></tr><tr><td>AAAA</td><td>IPv6 地址</td><td>IPv6 网络下使用</td></tr><tr><td>CNAME</td><td>另一个域名</td><td>接入 CDN 的业务域名几乎都使用 CNAME</td></tr><tr><td>MX</td><td>邮件服务器域名</td><td>邮件服务相关</td></tr><tr><td>TXT</td><td>任意文本</td><td>域名所有权验证、SPF/DKIM 等</td></tr><tr><td>NS</td><td>该域名的权威 DNS 服务器</td><td>域名委派管理</td></tr></tbody></table><h3 id="cdn-场景下为何使用-cname" tabindex="-1">CDN 场景下为何使用 CNAME <a class="header-anchor" href="#cdn-场景下为何使用-cname" aria-label="Permalink to &quot;CDN 场景下为何使用 CNAME&quot;">​</a></h3><p>接入 CDN 的网站,业务域名通常 CNAME 到 CDN 厂商提供的域名,而非直接配置 A 记录。原因:<strong>CDN 厂商的边缘节点 IP 是动态分配的</strong>——根据用户地理位置就近返回最优节点 IP,且节点列表频繁变化。业务方无法预测和写死这些 IP,只能通过 CNAME 把解析过程委托给 CDN,由 CDN 在解析时决定返回哪个边缘节点的 IP。</p><p>典型的解析链:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>www.example.com  CNAME  example.com.cdn-provider.net</span></span>
<span class="line"><span>example.com.cdn-provider.net  A  203.0.113.42  (北京用户解析得到的)</span></span>
<span class="line"><span>example.com.cdn-provider.net  A  198.51.100.13 (上海用户解析得到的)</span></span></code></pre></div><p><img src="`+n+'" alt="业务域名通过 CNAME 委托给 CDN 返回就近节点"></p><h3 id="dns-失败的两类判定信号" tabindex="-1">DNS 失败的两类判定信号 <a class="header-anchor" href="#dns-失败的两类判定信号" aria-label="Permalink to &quot;DNS 失败的两类判定信号&quot;">​</a></h3><table tabindex="0"><thead><tr><th>浏览器错误</th><th>含义</th><th>排查方向</th></tr></thead><tbody><tr><td><code>DNS_PROBE_FINISHED_NXDOMAIN</code></td><td>域名不存在</td><td>域名拼写错误、解析记录未配置、域名已过期</td></tr><tr><td><code>DNS_PROBE_FINISHED_NO_INTERNET</code></td><td>本机无法访问 DNS 服务器</td><td>本机网络故障、DNS 服务器不可达</td></tr></tbody></table><p>DNS 失败时,请求根本没有到达任何服务器,问题卡在第一步。</p><h2 id="三、tcp-连接与-tls-握手" tabindex="-1">三、TCP 连接与 TLS 握手 <a class="header-anchor" href="#三、tcp-连接与-tls-握手" aria-label="Permalink to &quot;三、TCP 连接与 TLS 握手&quot;">​</a></h2><p>DNS 解析返回 IP 后,浏览器需要与 <code>IP:端口</code> 建立 TCP 连接。HTTPS 默认端口 443,HTTP 默认端口 80。</p><h3 id="端口的作用" tabindex="-1">端口的作用 <a class="header-anchor" href="#端口的作用" aria-label="Permalink to &quot;端口的作用&quot;">​</a></h3><p>端口的存在意义是<strong>让一台机器可以同时承载多个网络服务</strong>。同一个 IP 上,22 端口运行 SSH、80 端口运行 HTTP、443 端口运行 HTTPS、3306 端口运行 MySQL——通过端口号区分不同服务。这些端口号属于业界约定的&quot;知名端口&quot;,变更需要客户端显式指定。</p><h3 id="tls-握手-https-特有的步骤" tabindex="-1">TLS 握手:HTTPS 特有的步骤 <a class="header-anchor" href="#tls-握手-https-特有的步骤" aria-label="Permalink to &quot;TLS 握手:HTTPS 特有的步骤&quot;">​</a></h3><p>HTTPS 在 TCP 连接建立后,还要进行 TLS 握手——客户端验证服务器证书的有效性,双方协商加密参数,后续通信全程加密。这一步可能在以下场景失败:</p><table tabindex="0"><thead><tr><th>TLS 失败现象</th><th>含义</th></tr></thead><tbody><tr><td><code>NET::ERR_CERT_DATE_INVALID</code></td><td>证书已过期或尚未生效(服务器时钟偏差也会触发)</td></tr><tr><td><code>NET::ERR_CERT_COMMON_NAME_INVALID</code></td><td>证书的域名与访问的域名不匹配</td></tr><tr><td><code>NET::ERR_CERT_AUTHORITY_INVALID</code></td><td>客户端不信任证书的签发机构</td></tr><tr><td><code>NET::ERR_CONNECTION_RESET</code></td><td>TLS 握手过程中连接被重置</td></tr></tbody></table><p>证书相关的故障在浏览器上表现为红色警告页,直接阻断访问。</p><h3 id="连接层错误-refused-vs-timed-out" tabindex="-1">连接层错误:REFUSED vs TIMED_OUT <a class="header-anchor" href="#连接层错误-refused-vs-timed-out" aria-label="Permalink to &quot;连接层错误:REFUSED vs TIMED_OUT&quot;">​</a></h3><p>如果连 TCP 连接都建立不起来,浏览器会报:</p><table tabindex="0"><thead><tr><th>错误</th><th>含义</th><th>排查方向</th></tr></thead><tbody><tr><td><code>ERR_CONNECTION_REFUSED</code></td><td>包到达对方,但端口没有服务监听(或被防火墙 reject)</td><td>服务端确认服务是否启动、端口是否监听</td></tr><tr><td><code>ERR_CONNECTION_TIMED_OUT</code></td><td>包根本没到达对方</td><td>网络路径、防火墙、安全组、目标主机离线</td></tr></tbody></table><p><strong>这两个错误反映的是完全不同的故障类别</strong>——<code>REFUSED</code> 是立即返回的,说明对方机器在线但服务不通;<code>TIMED_OUT</code> 是几十秒后才返回,说明包根本没到。混淆这两者会让排查方向完全跑偏。</p><p><img src="'+i+`" alt="连接被拒绝和连接超时的排查方向不同"></p><h2 id="四、http-请求" tabindex="-1">四、HTTP 请求 <a class="header-anchor" href="#四、http-请求" aria-label="Permalink to &quot;四、HTTP 请求&quot;">​</a></h2><p>TCP / TLS 连接建立后,浏览器开始发送 HTTP 请求。HTTP 本质是一个基于文本的协议,规定了客户端和服务器之间如何表达&quot;请求什么&quot;和&quot;返回什么&quot;。</p><h3 id="http-请求的核心组成" tabindex="-1">HTTP 请求的核心组成 <a class="header-anchor" href="#http-请求的核心组成" aria-label="Permalink to &quot;HTTP 请求的核心组成&quot;">​</a></h3><p>一个典型 HTTP 请求包含:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /docs/index.html HTTP/1.1</span></span>
<span class="line"><span>Host: www.example.com</span></span>
<span class="line"><span>User-Agent: Mozilla/5.0 ...</span></span>
<span class="line"><span>Accept: text/html</span></span>
<span class="line"><span>Cookie: session=abc123</span></span>
<span class="line"><span>Authorization: Bearer xxx</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(POST 请求才有 body)</span></span></code></pre></div><p>关键字段:</p><ul><li><strong>方法</strong>:<code>GET</code>(读)、<code>POST</code>(写)、<code>PUT</code>(更新)、<code>DELETE</code>(删除)、<code>HEAD</code>(只看响应头)</li><li><strong>路径</strong>:URL 中协议、域名、端口之后的部分</li><li><strong>Host 头</strong>:说明访问的是哪个域名</li><li><strong>Header</strong>:Cookie、认证信息、内容类型等元数据</li><li><strong>Body</strong>:POST/PUT 这类提交数据的请求才有</li></ul><h3 id="host-头的关键作用" tabindex="-1">Host 头的关键作用 <a class="header-anchor" href="#host-头的关键作用" aria-label="Permalink to &quot;Host 头的关键作用&quot;">​</a></h3><p><strong>同一个 IP 后端可能挂多个站点,服务器靠 Host 头区分</strong>。例如 <code>www.example.com</code> 和 <code>api.example.com</code> 可能解析到同一个 IP,但 Nginx 等 Web 服务器根据请求的 Host 头将请求转发到不同的后端应用。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20Browser%5B%22%E6%B5%8F%E8%A7%88%E5%99%A8%22%5D%0A%20%20Nginx%5B%22Nginx%20203.0.113.10%3A443%22%5D%0A%20%20WebApp%5B%22%E5%AE%98%E7%BD%91%E5%BA%94%E7%94%A8%20%3A8080%22%5D%0A%20%20ApiApp%5B%22API%20%E5%BA%94%E7%94%A8%20%3A9090%22%5D%0A%0A%20%20Browser%20--%3E%7C%22Host%3A%20www.example.com%22%7C%20Nginx%0A%20%20Browser%20--%3E%7C%22Host%3A%20api.example.com%22%7C%20Nginx%0A%20%20Nginx%20--%3E%7C%22Host%3Dwww%22%7C%20WebApp%0A%20%20Nginx%20--%3E%7C%22Host%3Dapi%22%7C%20ApiApp%0A"></div><p>缺失或错误的 Host 头会导致 Nginx 无法判断请求归属,通常返回默认站点或 404。</p><h3 id="http-响应的状态码分层" tabindex="-1">HTTP 响应的状态码分层 <a class="header-anchor" href="#http-响应的状态码分层" aria-label="Permalink to &quot;HTTP 响应的状态码分层&quot;">​</a></h3><p>请求发出后,服务器返回响应。HTTP 状态码按数字范围分类:</p><table tabindex="0"><thead><tr><th>范围</th><th>类别</th><th>含义</th></tr></thead><tbody><tr><td>1xx</td><td>信息性</td><td>临时响应,客户端继续操作</td></tr><tr><td>2xx</td><td>成功</td><td>请求被成功处理</td></tr><tr><td>3xx</td><td>重定向</td><td>资源被移到其他位置</td></tr><tr><td>4xx</td><td>客户端错误</td><td>请求本身有问题(语法、路径、权限)</td></tr><tr><td>5xx</td><td>服务端错误</td><td>服务器在处理请求过程中出错</td></tr></tbody></table><h2 id="五、入口层" tabindex="-1">五、入口层 <a class="header-anchor" href="#五、入口层" aria-label="Permalink to &quot;五、入口层&quot;">​</a></h2><p>公网请求进入业务程序之前,通常会经过多层入口组件。完整链路可能包括:</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20Browser%5B%22%E6%B5%8F%E8%A7%88%E5%99%A8%22%5D%0A%20%20DNS%5B%22DNS%22%5D%0A%20%20Edge%5B%22CDN%20%2F%20WAF%22%5D%0A%20%20LB%5B%22%E8%B4%9F%E8%BD%BD%E5%9D%87%E8%A1%A1%22%5D%0A%20%20Nginx%5B%22Nginx%20%2F%20Ingress%22%5D%0A%20%20App%5B%22%E5%90%8E%E7%AB%AF%E5%BA%94%E7%94%A8%22%5D%0A%20%20DB%5B%22%E6%95%B0%E6%8D%AE%E5%BA%93%22%5D%0A%0A%20%20Browser%20--%3E%20DNS%0A%20%20DNS%20--%3E%20Browser%0A%20%20Browser%20--%3E%20Edge%0A%20%20Edge%20--%3E%20LB%0A%20%20LB%20--%3E%20Nginx%0A%20%20Nginx%20--%3E%20App%0A%20%20App%20--%3E%20DB%0A"></div><p>每一层的职责:</p><ul><li><strong>CDN</strong> — 静态资源就近分发,减少源站压力</li><li><strong>WAF</strong> — Web 应用防火墙,过滤恶意请求(SQL 注入、XSS、爬虫)</li><li><strong>负载均衡</strong> — 把流量分摊到多个后端实例</li><li><strong>Nginx / Ingress</strong> — 反向代理,按域名、路径分发请求</li><li><strong>后端应用</strong> — 实际处理业务逻辑</li></ul><p>小型站点可能只有&quot;云服务器 + Nginx&quot;两层,大型业务系统每一层都是独立的集群。</p><h3 id="状态码作为故障分层的线索" tabindex="-1">状态码作为故障分层的线索 <a class="header-anchor" href="#状态码作为故障分层的线索" aria-label="Permalink to &quot;状态码作为故障分层的线索&quot;">​</a></h3><p>5xx 与 4xx 状态码本身就是故障分层的最直接线索:</p><table tabindex="0"><thead><tr><th>状态码</th><th>含义</th><th>问题位置</th></tr></thead><tbody><tr><td>404</td><td>资源未找到</td><td>路径错误、Nginx 路由配置、后端路由</td></tr><tr><td>401</td><td>未认证</td><td>用户未登录或 token 无效</td></tr><tr><td>403</td><td>已认证但无权限</td><td>授权策略拒绝</td></tr><tr><td>500</td><td>服务器内部错误</td><td><strong>后端处理过程中出错</strong>(代码异常、数据库异常)</td></tr><tr><td>502</td><td>Bad Gateway</td><td><strong>入口层连不上后端</strong>(后端进程未启动、端口错、连接被拒)</td></tr><tr><td>503</td><td>服务不可用</td><td>后端实例不可用、过载、健康检查失败</td></tr><tr><td>504</td><td>Gateway Timeout</td><td>入口层等后端超时</td></tr></tbody></table><h3 id="_500-与-502-的本质区别" tabindex="-1">500 与 502 的本质区别 <a class="header-anchor" href="#_500-与-502-的本质区别" aria-label="Permalink to &quot;500 与 502 的本质区别&quot;">​</a></h3><p>500 与 502 经常被混淆,但反映完全不同的问题:</p><ul><li><strong>500</strong> — 后端<strong>收到了</strong>请求,但在处理过程中报错(代码异常、SQL 错误、外部 API 调用失败)。<strong>排查方向是后端应用日志</strong>——日志中通常有完整的异常堆栈。</li><li><strong>502</strong> — 入口层<strong>根本没有连上</strong>后端。<strong>排查方向是入口层(Nginx/Ingress)的 error log</strong>,典型错误: <ul><li><code>connect() failed (111: Connection refused)</code> — 后端端口没有服务监听</li><li><code>no live upstreams while connecting to upstream</code> — 所有后端实例健康检查失败</li><li><code>upstream prematurely closed connection</code> — 后端进程崩溃了</li></ul></li></ul><p>混淆这两个状态码会让排查方向完全错位——把&quot;后端进程没起来&quot;的 502 当成&quot;代码 bug&quot;的 500 去查应用日志,显然找不到结果。</p><p><img src="`+l+'" alt="500 看应用日志，502 看入口日志"></p><h2 id="六、页面资源加载" tabindex="-1">六、页面资源加载 <a class="header-anchor" href="#六、页面资源加载" aria-label="Permalink to &quot;六、页面资源加载&quot;">​</a></h2><p>服务器返回 HTML 后,<strong>浏览器才开始真正&quot;打开&quot;这个页面</strong>。HTML 中引用的 CSS、JavaScript、图片、字体等资源,浏览器会再发起新的请求去拉取。一个网页打开背后,Network 面板里通常有几十甚至上百个请求。</p><h3 id="前后端分离应用的访问链路更长" tabindex="-1">前后端分离应用的访问链路更长 <a class="header-anchor" href="#前后端分离应用的访问链路更长" aria-label="Permalink to &quot;前后端分离应用的访问链路更长&quot;">​</a></h3><p>前后端分离架构下,首次请求往往只返回一个 <code>index.html</code> 骨架和若干 JS/CSS 文件。<strong>真正的业务数据通过 JavaScript 在浏览器运行后,再调用 <code>/api/...</code> 接口获取</strong>。这意味着:</p><ul><li>页面打开慢,可能不是初始 HTML 慢,而是后续某个 JS bundle 过大或某个 API 请求超时</li><li>用户看到&quot;页面打开但内容一直转圈&quot;,通常是 API 请求(后端或数据库)的问题,而不是 HTML 自身的问题</li></ul><p>完整的请求链路时序:</p><div class="mermaid-diagram" data-mermaid-code="sequenceDiagram%0A%20%20autonumber%0A%20%20participant%20Browser%20as%20%E6%B5%8F%E8%A7%88%E5%99%A8%0A%20%20participant%20DNS%20as%20DNS%E8%A7%A3%E6%9E%90%0A%20%20participant%20Entry%20as%20%E5%85%A5%E5%8F%A3%E5%B1%82%0A%20%20participant%20Web%20as%20Web%E6%9C%8D%E5%8A%A1%0A%20%20participant%20App%20as%20%E5%90%8E%E7%AB%AF%E5%BA%94%E7%94%A8%0A%20%20participant%20DB%20as%20%E6%95%B0%E6%8D%AE%E5%BA%93%0A%0A%20%20Browser-%3E%3EDNS%3A%20%E6%9F%A5%E8%AF%A2%20www.example.com%0A%20%20DNS--%3E%3EBrowser%3A%20%E8%BF%94%E5%9B%9E%20IP%20%E6%88%96%20CDN%20%E8%8A%82%E7%82%B9%20IP%0A%20%20Browser-%3E%3EEntry%3A%20%E8%BF%9E%E6%8E%A5%20IP%3A443%2C%E5%AE%8C%E6%88%90%20TCP%2FTLS%0A%20%20Browser-%3E%3EEntry%3A%20%E5%8F%91%E9%80%81%20HTTP%20%E8%AF%B7%E6%B1%82%0A%20%20Entry-%3E%3EWeb%3A%20%E8%BD%AC%E5%8F%91%E5%88%B0%20Web%20%E6%9C%8D%E5%8A%A1%0A%20%20Web-%3E%3EApp%3A%20%E5%8A%A8%E6%80%81%E8%AF%B7%E6%B1%82%E4%BA%A4%E7%BB%99%E5%90%8E%E7%AB%AF%E5%BA%94%E7%94%A8%0A%20%20App-%3E%3EDB%3A%20%E6%9F%A5%E8%AF%A2%E6%88%96%E5%86%99%E5%85%A5%E6%95%B0%E6%8D%AE%0A%20%20DB--%3E%3EApp%3A%20%E8%BF%94%E5%9B%9E%E6%95%B0%E6%8D%AE%0A%20%20App--%3E%3EWeb%3A%20%E8%BF%94%E5%9B%9E%20HTML%20%E6%88%96%20JSON%0A%20%20Web--%3E%3EBrowser%3A%20%E8%BF%94%E5%9B%9E%E7%8A%B6%E6%80%81%E7%A0%81%E3%80%81%E5%93%8D%E5%BA%94%E5%A4%B4%E3%80%81%E5%93%8D%E5%BA%94%E4%BD%93%0A%20%20Browser-%3E%3EEntry%3A%20%E7%BB%A7%E7%BB%AD%E8%AF%B7%E6%B1%82%20CSS%E3%80%81JS%E3%80%81%E5%9B%BE%E7%89%87%E5%92%8C%20API%0A"></div><h2 id="七、按现象快速分层定位" tabindex="-1">七、按现象快速分层定位 <a class="header-anchor" href="#七、按现象快速分层定位" aria-label="Permalink to &quot;七、按现象快速分层定位&quot;">​</a></h2><p>排查&quot;网站访问异常&quot;的核心方法是<strong>根据用户侧的现象,直接定位到大概率的故障层</strong>,而不是从头开始逐层查。</p><table tabindex="0"><thead><tr><th>用户侧现象</th><th>可能位置</th><th>排查方向</th></tr></thead><tbody><tr><td>浏览器报 <code>DNS_PROBE_FINISHED_NXDOMAIN</code></td><td>DNS</td><td>域名拼写、解析记录、本机 DNS 缓存</td></tr><tr><td>浏览器报 <code>ERR_CERT_*</code>(红色警告页)</td><td>TLS</td><td>证书有效期、域名匹配、签发机构信任</td></tr><tr><td><code>ERR_CONNECTION_REFUSED</code>(立即返回)</td><td>连接层</td><td>服务进程未启动、端口监听错误</td></tr><tr><td><code>ERR_CONNECTION_TIMED_OUT</code>(几十秒后返回)</td><td>网络层</td><td>防火墙、安全组、路由、对方主机离线</td></tr><tr><td>返回 404</td><td>路由层</td><td>Nginx 路由配置、后端路由表</td></tr><tr><td>返回 401</td><td>认证</td><td>登录失效、token 过期</td></tr><tr><td>返回 403</td><td>权限</td><td>用户角色、资源 ACL</td></tr><tr><td>返回 500</td><td>后端应用</td><td><strong>应用日志中的异常堆栈</strong></td></tr><tr><td>返回 502</td><td>入口到后端</td><td><strong>入口层(Nginx)的 error log</strong></td></tr><tr><td>返回 503</td><td>后端容量/健康检查</td><td>实例数量、健康检查状态、限流策略</td></tr><tr><td>返回 504</td><td>后端响应慢</td><td>后端慢查询、外部 API 调用超时</td></tr><tr><td>页面打开但内容转圈</td><td>接口层</td><td>浏览器 Network 看具体哪个 API 请求异常</td></tr></tbody></table><p>这套&quot;按现象定位&quot;的方法是网站故障排查的基础。后续每一讲会展开具体某一层的实现细节、配置方式、典型故障——本讲建立的是整体的层次认知,后续排查时回到这个全景图,知道每一步在查什么、为什么这么查。</p>',78)])])}const T=d(p,[["render",c]]);export{u as __pageData,T as default};
